import os

try:
	import pg8000
except ImportError as e:
	raise ImportError(
		"pg8000 is not installed. Install in your venv: `python -m pip install pg8000`"
	) from e


def _get_cfg():
	return {
		"host": os.getenv("DB_HOST", "localhost"),
		"port": int(os.getenv("DB_PORT", "5432")),
		"database": os.getenv("DB_NAME", "postgres"),
		# default to current OS user — often a matching Postgres role exists
		"user": os.getenv("DB_USER", os.getenv("USER") or os.getlogin()),
		"password": os.getenv("DB_PASS", ""),
	}


def get_conn():
	cfg = _get_cfg()
	return pg8000.connect(
		host=cfg["host"],
		port=cfg["port"],
		user=cfg["user"],
		password=cfg["password"],
		database=cfg["database"],
	)


def check_user(username: str, password: str) -> bool:
	"""Return True if username exists and password matches (plaintext)."""
	if not username:
		return False
	conn = None
	cur = None
	try:
		conn = get_conn()
		cur = conn.cursor()
		cur.execute("SELECT password FROM users WHERE username = %s", (username,))
		row = cur.fetchone()
		if not row:
			return False
		stored = row[0]
		return stored == password
	finally:
		try:
			if cur:
				cur.close()
		except Exception:
			pass
		try:
			if conn:
				conn.close()
		except Exception:
			pass


def test_connection() -> bool:
	conn = None
	cur = None
	try:
		conn = get_conn()
		cur = conn.cursor()
		cur.execute("SELECT 1")
		_ = cur.fetchone()
		return True
	finally:
		try:
			if cur:
				cur.close()
		except Exception:
			pass
		try:
			if conn:
				conn.close()
		except Exception:
			pass


def list_users():
	"""Return a list of usernames in the users table."""
	conn = None
	cur = None
	try:
		conn = get_conn()
		cur = conn.cursor()
		cur.execute("SELECT username FROM users ORDER BY id")
		return [row[0] for row in cur.fetchall()]
	finally:
		try:
			if cur:
				cur.close()
		except Exception:
			pass
		try:
			if conn:
				conn.close()
		except Exception:
			pass


def add_user(username: str, password: str) -> bool:
	"""Add a user with plaintext password. Returns True if added, False if exists."""
	if not username:
		return False
	conn = None
	cur = None
	try:
		conn = get_conn()
		cur = conn.cursor()
		cur.execute("INSERT INTO users (username,password) VALUES (%s,%s) ON CONFLICT (username) DO NOTHING", (username, password))
		conn.commit()
		# check whether inserted
		cur.execute("SELECT 1 FROM users WHERE username = %s", (username,))
		return cur.fetchone() is not None
	finally:
		try:
			if cur:
				cur.close()
		except Exception:
			pass
		try:
			if conn:
				conn.close()
		except Exception:
			pass


def delete_user(username: str) -> bool:
	"""Delete a user by username. Returns True if a row was deleted."""
	if not username:
		return False
	conn = None
	cur = None
	try:
		conn = get_conn()
		cur = conn.cursor()
		cur.execute("DELETE FROM users WHERE username = %s", (username,))
		deleted = cur.rowcount
		conn.commit()
		return deleted > 0
	finally:
		try:
			if cur:
				cur.close()
		except Exception:
			pass
		try:
			if conn:
				conn.close()
		except Exception:
			pass

import os

try:
	import pg8000
except ImportError as e:
	raise ImportError("pg8000 is not installed. Install in your venv: `python -m pip install pg8000`") from e


def _get_cfg():
	return {
		"host": os.getenv("DB_HOST", "localhost"),
		"port": int(os.getenv("DB_PORT", "5432")),
		"database": os.getenv("DB_NAME", "postgres"),
		# default to current OS user — often a matching Postgres role exists
		"user": os.getenv("DB_USER", os.getenv("USER") or os.getlogin()),
		"password": os.getenv("DB_PASS", ""),
	}


def get_conn():
	cfg = _get_cfg()
	return pg8000.connect(
		host=cfg["host"],
		port=cfg["port"],
		user=cfg["user"],
		password=cfg["password"],
		database=cfg["database"],
	)


def ensure_schema():
	"""Ensure users table has required columns: role, blocked, failed_attempts."""
	conn = None
	cur = None
	try:
		conn = get_conn()
		cur = conn.cursor()
		# create table if not exists with base columns
		cur.execute(
			"""
			CREATE TABLE IF NOT EXISTS users (
				id serial PRIMARY KEY,
				username text UNIQUE NOT NULL,
				password text NOT NULL
			)
			"""
		)
		# add additional columns if missing
		cur.execute("ALTER TABLE users ADD COLUMN IF NOT EXISTS role text DEFAULT 'user'")
		cur.execute("ALTER TABLE users ADD COLUMN IF NOT EXISTS blocked boolean DEFAULT false")
		cur.execute("ALTER TABLE users ADD COLUMN IF NOT EXISTS failed_attempts integer DEFAULT 0")
		conn.commit()
	finally:
		try:
			if cur:
				cur.close()
		except Exception:
			pass
		try:
			if conn:
				conn.close()
		except Exception:
			pass


def get_user(username: str):
	"""Return dict with user info or None."""
	if not username:
		return None
	conn = None
	cur = None
	try:
		conn = get_conn()
		cur = conn.cursor()
		cur.execute("SELECT id, username, password, role, blocked, failed_attempts FROM users WHERE username = %s", (username,))
		row = cur.fetchone()
		if not row:
			return None
		return {
			'id': row[0],
			'username': row[1],
			'password': row[2],
			'role': row[3],
			'blocked': row[4],
			'failed_attempts': row[5],
		}
	finally:
		try:
			if cur:
				cur.close()
		except Exception:
			pass
		try:
			if conn:
				conn.close()
		except Exception:
			pass


def increment_failed(username: str) -> tuple[int, bool]:
	"""Increment failed_attempts for a user. If reaches 3, set blocked=True.
	Returns (failed_attempts, blocked).
	If user does not exist returns (0, False).
	"""
	if not username:
		return 0, False
	conn = None
	cur = None
	try:
		conn = get_conn()
		cur = conn.cursor()
		cur.execute("UPDATE users SET failed_attempts = COALESCE(failed_attempts,0) + 1 WHERE username = %s RETURNING failed_attempts", (username,))
		row = cur.fetchone()
		if not row:
			return 0, False
		attempts = row[0] or 0
		blocked = False
		if attempts >= 3:
			cur.execute("UPDATE users SET blocked = true WHERE username = %s", (username,))
			blocked = True
		conn.commit()
		return attempts, blocked
	finally:
		try:
			if cur:
				cur.close()
		except Exception:
			pass
		try:
			if conn:
				conn.close()
		except Exception:
			pass


def reset_failed(username: str):
	if not username:
		return
	conn = None
	cur = None
	try:
		conn = get_conn()
		cur = conn.cursor()
		cur.execute("UPDATE users SET failed_attempts = 0 WHERE username = %s", (username,))
		conn.commit()
	finally:
		try:
			if cur:
				cur.close()
		except Exception:
			pass
		try:
			if conn:
				conn.close()
		except Exception:
			pass


