def update_user(username: str, password: str = None, role: str = None, blocked: bool = None) -> bool:
	"""Update user's password, role, and/or blocked flag.

	Only parameters not None are updated. Returns True if a row was updated.
	"""
	if not username:
		return False
	conn = None
	cur = None
	try:
		conn = get_conn()
		cur = conn.cursor()
		parts = []
		vals = []
		if password is not None:
			parts.append("password = %s")
			vals.append(password)
		if role is not None:
			parts.append("role = %s")
			vals.append(role)
		if blocked is not None:
			parts.append("blocked = %s")
			vals.append(blocked)
		if not parts:
			return False
		vals.append(username)
		sql = "UPDATE users SET " + ", ".join(parts) + " WHERE username = %s"
		cur.execute(sql, tuple(vals))
		updated = cur.rowcount
		conn.commit()
		return updated > 0
	finally:
		try:
			if cur:
				cur.close()
		except Exception:
			pass
		try:
			if conn:
				conn.close()
		except Exception:
			pass

import tkinter as tk from tkinter import messagebox import threading
from db import check_user, list_users, add_user, delete_user import random
class LoginWindow(tk.Tk): def __init__(self): super().__init__() self.title("Login") self.geometry("380x240") self.create_widgets()
def create_widgets(self): tk.Label(self, text="Username:").grid(row=0, column=0, sticky="w", padx=10, pady=(10, 0)) self.e_user = tk.Entry(self) self.e_user.grid(row=0, column=1, padx=10, pady=(10, 0))
tk.Label(self, text="Password:").grid(row=1, column=0, sticky="w", padx=10, pady=(6, 0)) self.e_pass = tk.Entry(self, show='*') self.e_pass.grid(row=1, column=1, padx=10, pady=(6, 0))
# simple text captcha self.captcha_value = self._gen_captcha() tk.Label(self, text="Enter captcha:").grid(row=2, column=0, sticky="w", padx=10, pady=(6, 0)) self.captcha_label = tk.Label(self, text=self.captcha_value, font=(None, 14, 'bold')) self.captcha_label.grid(row=2, column=1, sticky="w", padx=10, pady=(6, 0))
self.captcha_entry = tk.Entry(self) self.captcha_entry.grid(row=3, column=1, padx=10, pady=(6, 0))
self.login_btn = tk.Button(self, text="Login", command=self.do_Login) self.login_btn.grid(row=2, column=0, columnspan=2, pady=20)
def do_Login(self): username = self.e_user.get().strip() password = self.e_pass.get().strip() captcha_in = self.captcha_entry.get().strip() if not username or not password: messagebox.showwarning("Warning", "Please enter both username and password") return if captcha_in != self.captcha_value: messagebox.showwarning('Captcha', 'Captcha does not match') # regenerate captcha self.captcha_value = self._gen_captcha() self.captcha_label.config(text=self.captcha_value) return
# disable button while checking self.login_btn.config(state='disabled')
def worker(u, p): try: ok = check_user(u, p) # post result back to main thread self.after(0, self._on_result, ok, None) except Exception as e: self.after(0, self._on_result, False, e)
threading.Thread(target=worker, args=(username, password), daemon=True).start()
def _on_result(self, ok, error): self.login_btn.config(state='normal') if error: messagebox.showerror('DB error', str(error)) return if ok: messagebox.showinfo('Login', 'Success') # open user manager window self.open_user_manager() else: messagebox.showerror('Login', 'Invalid username/password')
def _gen_captcha(self): return ''.join(str(random.randint(0, 9)) for _ in range(4))
def open_user_manager(self): um = UserManager(self) um.grab_set()
class UserManager(tk.Toplevel): def __init__(self, parent): super().__init__(parent) self.title('User manager') self.geometry('420x320') self.create_widgets() self.refresh()
def create_widgets(self): self.user_listbox = tk.Listbox(self) self.user_listbox.pack(fill='both', expand=True, padx=10, pady=10)
frm = tk.Frame(self) frm.pack(fill='x', padx=10) tk.Label(frm, text='Username').grid(row=0, column=0) self.nu = tk.Entry(frm) self.nu.grid(row=0, column=1) tk.Label(frm, text='Password').grid(row=1, column=0) self.np = tk.Entry(frm) self.np.grid(row=1, column=1)
btn_frame = tk.Frame(self) btn_frame.pack(fill='x', padx=10, pady=8) tk.Button(btn_frame, text='Add', command=self.add_user_ui).pack(side='left') tk.Button(btn_frame, text='Delete', command=self.delete_user_ui).pack(side='left') tk.Button(btn_frame, text='Refresh', command=self.refresh).pack(side='left')
def refresh(self): try: users = list_users() except Exception as e: messagebox.showerror('DB error', str(e)) return self.user_listbox.delete(0, 'end') for u in users: self.user_listbox.insert('end', u)
def add_user_ui(self): username = self.nu.get().strip() password = self.np.get().strip() if not username or not password: messagebox.showwarning('Input', 'Enter username and password') return try: ok = add_user(username, password) if ok: messagebox.showinfo('Added', 'User added') self.refresh() else: messagebox.showwarning('Exists', 'User already exists') except Exception as e: messagebox.showerror('DB error', str(e))
def delete_user_ui(self): sel = self.user_listbox.curselection() if not sel: messagebox.showwarning('Select', 'Select a user to delete') return username = self.user_listbox.get(sel[0]) if not messagebox.askyesno('Confirm', f'Delete user {username}?'): return try: ok = delete_user(username) if ok: messagebox.showinfo('Deleted', 'User deleted') self.refresh() else: messagebox.showwarning('Not found', 'User not found') except Exception as e: messagebox.showerror('DB error', str(e))
if __name__ == "__main__": app = LoginWindow() app.mainloop()

import tkinter as tk from tkinter import messagebox import threading
from db import ( check_user, authenticate_user, list_users, add_user, delete_user, block_user, unlock_user, ensure_schema, increment_failed, update_user, get_user, ) import random
# Try to use Pillow for better image resizing; fallback if not installed try: from PIL import Image, ImageTk _HAS_PIL = True except Exception: _HAS_PIL = False
# size in pixels for each puzzle tile TILE_SIZE = 100
class PuzzleCaptcha(tk.Frame): """Simple 2x2 puzzle captcha using images from capchaImage folder.
Click one tile, then another to swap. When tiles are in correct order (1,2,3,4) captcha is solved. """ def __init__(self, parent, image_dir='capchaImage'): super().__init__(parent) self.image_dir = image_dir self.correct = [0, 1, 2, 3] self.state = list(self.correct) self.images = [] # PhotoImage refs self.buttons = [] self.selected = None self.solved = False self._load_images() self._build_ui() self.shuffle()
def _load_images(self): self.images.clear() for i in range(1, 5): path = f"{self.image_dir}/{i}.png" try: if _HAS_PIL: # load with Pillow and resize to TILE_SIZE pil = Image.open(path).convert('RGBA') pil = pil.resize((TILE_SIZE, TILE_SIZE), Image.LANCZOS) img = ImageTk.PhotoImage(pil) else: # load with Tk and subsample if too large raw = tk.PhotoImage(file=path) w = raw.width() h = raw.height() # compute integer subsample factor to fit TILE_SIZE factor = max(1, int(max(w, h) / TILE_SIZE)) if factor > 1: img = raw.subsample(factor, factor) else: img = raw except Exception: # fallback: create a simple image-like label using text img = None self.images.append(img)
def _build_ui(self): # 2x2 grid of buttons for pos in range(4): btn = tk.Button(self, command=lambda p=pos: self.on_click(p)) r = pos // 2 c = pos % 2 btn.grid(row=r, column=c, padx=2, pady=2, ipadx=10, ipady=10) self.buttons.append(btn) # shuffle button sh = tk.Button(self, text='Shuffle', command=self.shuffle) sh.grid(row=2, column=0, columnspan=2, pady=(6, 0))
def _update_buttons(self): for pos, btn in enumerate(self.buttons): tile = self.state[pos] img = self.images[tile] if img: btn.config(image=img, text='') btn.image = img else: # fallback to text label btn.config(text=str(tile + 1), image='')
# visual selected state if self.selected is not None and self.selected == pos: btn.config(relief='sunken') else: btn.config(relief='raised')
def on_click(self, pos): if self.solved: return if self.selected is None: self.selected = pos self._update_buttons() return if self.selected == pos: self.selected = None self._update_buttons() return # swap self.state[self.selected], self.state[pos] = self.state[pos], self.state[self.selected] self.selected = None self._update_buttons() self._check_solved()
def shuffle(self): import random as _r # randomize until different from correct _r.shuffle(self.state) if self.state == self.correct: _r.shuffle(self.state) self.solved = False self.selected = None self._update_buttons()
def _check_solved(self): if self.state == self.correct: self.solved = True # indicate solved (disable buttons) for b in self.buttons: b.config(state='disabled')
def is_solved(self): return self.solved
class LoginWindow(tk.Tk): def __init__(self): super().__init__() self.title("Login") self.geometry("380x240") self.create_widgets()
def create_widgets(self): tk.Label(self, text="Username:").grid(row=0, column=0, sticky="w", padx=10, pady=(10, 0)) self.e_user = tk.Entry(self) self.e_user.grid(row=0, column=1, padx=10, pady=(10, 0))
tk.Label(self, text="Password:").grid(row=1, column=0, sticky="w", padx=10, pady=(6, 0)) self.e_pass = tk.Entry(self, show='*') self.e_pass.grid(row=1, column=1, padx=10, pady=(6, 0)) # puzzle captcha (image puzzle from capchaImage/1..4.png) self.captcha = PuzzleCaptcha(self) self.captcha.grid(row=2, column=0, columnspan=2, pady=(8, 0))
self.login_btn = tk.Button(self, text="Login", command=self.do_Login) self.login_btn.grid(row=3, column=0, columnspan=2, pady=12)
def do_Login(self): username = self.e_user.get().strip() password = self.e_pass.get().strip() if not username or not password: messagebox.showwarning("Warning", "Please enter both username and password") return if not getattr(self, 'captcha', None) or not self.captcha.is_solved(): messagebox.showwarning('Captcha', 'Please solve the puzzle captcha') # if username provided, count as failed attempt if username: try: attempts, blocked = increment_failed(username) if blocked: messagebox.showerror('Заблокировано', 'Вы заблокированы. Обратитесь к администратору') except Exception: pass return
# disable button while checking self.login_btn.config(state='disabled')
def worker(u, p): try: res = authenticate_user(u, p) # post result back to main thread self.after(0, self._on_auth_result, u, res) except Exception as e: self.after(0, self._on_result, False, e)
threading.Thread(target=worker, args=(username, password), daemon=True).start()
def _on_result(self, ok, error): # fallback error handler self.login_btn.config(state='normal') if error: messagebox.showerror('Ошибка БД', str(error)) return
def _on_auth_result(self, username, res: dict): self.login_btn.config(state='normal') if not res: messagebox.showerror('Ошибка', 'Ошибка аутентификации') return if res.get('blocked'): messagebox.showerror('Заблокировано', 'Вы заблокированы. Обратитесь к администратору') return if res.get('ok'): messagebox.showinfo('Успех', 'Вы успешно авторизовались') # open user manager if admin if res.get('role') == 'admin': self.open_user_manager() return # not ok and not blocked -> wrong password reason = res.get('reason') attempts = res.get('attempts', 0) if reason == 'wrong_password': if attempts >= 3: messagebox.showerror('Заблокировано', 'Вы заблокированы. Обратитесь к администратору') else: messagebox.showerror('Ошибка', 'Вы ввели неверный логин или пароль. Пожалуйста проверьте ещё раз введенные данные') return if reason == 'no_user': messagebox.showerror('Ошибка', 'Вы ввели неверный логин или пароль. Пожалуйста проверьте ещё раз введенные данные') return
def _gen_captcha(self): return ''.join(str(random.randint(0, 9)) for _ in range(4))
def open_user_manager(self): um = UserManager(self) um.grab_set()
class UserManager(tk.Toplevel): def __init__(self, parent): super().__init__(parent) self.title('User manager') self.geometry('420x320') self.create_widgets() self.refresh()
def create_widgets(self): self.user_listbox = tk.Listbox(self) self.user_listbox.pack(fill='both', expand=True, padx=10, pady=10)
frm = tk.Frame(self) frm.pack(fill='x', padx=10) tk.Label(frm, text='Username').grid(row=0, column=0) self.nu = tk.Entry(frm) self.nu.grid(row=0, column=1) tk.Label(frm, text='Password').grid(row=1, column=0) self.np = tk.Entry(frm) self.np.grid(row=1, column=1) tk.Label(frm, text='Role').grid(row=2, column=0) self.role_var = tk.StringVar(value='user') self.role_menu = tk.OptionMenu(frm, self.role_var, 'user', 'admin') self.role_menu.grid(row=2, column=1)
btn_frame = tk.Frame(self) btn_frame.pack(fill='x', padx=10, pady=8) tk.Button(btn_frame, text='Add', command=self.add_user_ui).pack(side='left') tk.Button(btn_frame, text='Load', command=self.load_user_ui).pack(side='left') tk.Button(btn_frame, text='Update', command=self.update_user_ui).pack(side='left') tk.Button(btn_frame, text='Delete', command=self.delete_user_ui).pack(side='left') tk.Button(btn_frame, text='Unblock', command=self.unblock_user_ui).pack(side='left') tk.Button(btn_frame, text='Refresh', command=self.refresh).pack(side='left')
def refresh(self): try: users = list_users() except Exception as e: messagebox.showerror('DB error', str(e)) return self.user_listbox.delete(0, 'end') for u in users: self.user_listbox.insert('end', u)
def add_user_ui(self): username = self.nu.get().strip() password = self.np.get().strip() role = self.role_var.get() if not username or not password: messagebox.showwarning('Input', 'Enter username and password') return try: ok = add_user(username, password, role) if ok: messagebox.showinfo('Added', 'User added') self.refresh() else: messagebox.showwarning('Exists', 'User already exists') except Exception as e: messagebox.showerror('DB error', str(e))
def unblock_user_ui(self): sel = self.user_listbox.curselection() if not sel: messagebox.showwarning('Select', 'Select a user to unblock') return username = self.user_listbox.get(sel[0]) try: unlock_user(username) messagebox.showinfo('OK', 'Пользователь разблокирован') self.refresh() except Exception as e: messagebox.showerror('DB error', str(e))
def load_user_ui(self): sel = self.user_listbox.curselection() if not sel: messagebox.showwarning('Select', 'Select a user to load') return username = self.user_listbox.get(sel[0]) try: u = get_user(username) if not u: messagebox.showwarning('Not found', 'User not found') return self.nu.delete(0, 'end') self.nu.insert(0, u['username']) self.np.delete(0, 'end') # do not prefill real password in UI for security; leave blank self.role_var.set(u.get('role') or 'user') except Exception as e: messagebox.showerror('DB error', str(e))
def update_user_ui(self): username = self.nu.get().strip() password = self.np.get().strip() role = self.role_var.get() if not username: messagebox.showwarning('Input', 'Enter username') return try: # if password empty, don't change it pwd = password if password else None ok = update_user(username, password=pwd, role=role) if ok: messagebox.showinfo('Updated', 'User updated') self.refresh() else: messagebox.showwarning('Not changed', 'No changes applied or user not found') except Exception as e: messagebox.showerror('DB error', str(e))
def delete_user_ui(self): sel = self.user_listbox.curselection() if not sel: messagebox.showwarning('Select', 'Select a user to delete') return username = self.user_listbox.get(sel[0]) if not messagebox.askyesno('Confirm', f'Delete user {username}?'): return try: ok = delete_user(username) if ok: messagebox.showinfo('Deleted', 'User deleted') self.refresh() else: messagebox.showwarning('Not found', 'User not found') except Exception as e: messagebox.showerror('DB error', str(e))
if __name__ == "__main__": # ensure DB schema exists (columns etc.) try: ensure_schema() except Exception as e: print('Failed to ensure DB schema:', e) app = LoginWindow() app.mainloop()
